/**
 * Convierte un string base64 a Blob
 */
export const base64ToBlob = (base64Data, contentType) => {
  const binary = atob(base64Data)
  const len = binary.length
  const bytes = new Uint8Array(len)
  for (let i = 0; i < len; i++) bytes[i] = binary.charCodeAt(i)
  return new Blob([bytes], { type: contentType })
}

/**
 * Descarga un archivo desde base64
 */
export const descargarArchivo = (base64Data, fileName, contentType) => {
  try {
    const byteCharacters = atob(base64Data)
    const byteNumbers = new Uint8Array(byteCharacters.length)
    for (let i = 0; i < byteCharacters.length; i++) {
      byteNumbers[i] = byteCharacters.charCodeAt(i)
    }
    const blob = new Blob([byteNumbers], { type: contentType })
    const url = URL.createObjectURL(blob)
    const link = document.createElement('a')
    link.href = url
    link.download = fileName
    document.body.appendChild(link)
    link.click()
    document.body.removeChild(link)
    URL.revokeObjectURL(url)
  } catch (error) {
    console.error('Error al descargar el archivo:', error)
  }
}

/**
 * Descarga un PDF desde base64
 */
export const descargarPdfBase64 = (data, nombre_archivo) => {
  const pdfLink = `data:application/pdf;base64,${data}`
  const downloadLink = document.createElement('a')
  downloadLink.href = pdfLink
  downloadLink.download = nombre_archivo
  downloadLink.click()
}
